import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"西堤六桥","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/xidi-bridges.md","filePath":"landmarks/summer-palace/xidi-bridges.md","lastUpdated":1784720050000}'),r={name:"landmarks/summer-palace/xidi-bridges.md"};function i(d,t,n,s,u,q){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="西堤六桥" tabindex="-1">西堤六桥 <a class="header-anchor" href="#西堤六桥" aria-label="Permalink to &quot;西堤六桥&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1769628357927-54b9d24e183d?w=1200&amp;q=80" alt="西堤六桥"></p><blockquote><p>&quot;六桥横绝天汉上，北山始与南屏通。&quot; —— 苏堤的诗魂，被乾隆写进了昆明湖</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>西堤是昆明湖西部一道狭长的湖堤，北起玉带桥、南至绣绮桥，堤上自北向南依次坐落着界湖桥、豳风桥、玉带桥、镜桥、练桥、柳桥六座桥梁，合称&quot;西堤六桥&quot;。</p><p>这道堤、这六桥，是乾隆仿杭州西湖苏堤而建的&quot;致敬之作&quot;：西湖苏堤亦有六桥（映波、锁澜、望山、压堤、东浦、跨虹），乾隆南巡归来，便将这份江南诗意移植到北京西郊，让昆明湖有了自己的&quot;苏堤春晓&quot;。</p><p>六桥各有形制、各有意境：高拱的、平卧的、亭桥相覆的、石桥素雅的，桥桥不同，景随步换。每座桥头原有乾隆御题诗碑，桥名本身亦是一段典故——&quot;豳风&quot;出自《诗经》豳风篇，寓劝课农桑；&quot;镜&quot;&quot;练&quot;二字则化用南朝谢朓名句&quot;余霞散成绮，澄江静如练&quot;。一道长堤，六座小桥，把诗三百篇、六朝文章与西湖烟雨统统收纳进一湖碧水之中。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆十五年（1750）</td><td style="text-align:left;">扩建昆明湖时筑西堤，仿西湖苏堤设六桥</td></tr><tr><td style="text-align:left;">乾隆年间</td><td style="text-align:left;">逐桥题名、逐桥立御制诗碑</td></tr><tr><td style="text-align:left;">清光绪十二年（1886）</td><td style="text-align:left;">堤北耕织图旧址建昆明湖水操学堂，为重建园林张目</td></tr><tr><td style="text-align:left;">咸丰年间</td><td style="text-align:left;">豳风桥（旧名桑苎桥）因避咸丰帝奕詝名讳改今名</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">春季&quot;西堤桃花&quot;成为京城赏花盛事</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">桥名</th><th style="text-align:left;">形制</th><th style="text-align:left;">典故与看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>界湖桥</strong></td><td style="text-align:left;">三孔石桥，平直舒展</td><td style="text-align:left;">地处西堤最北端，为内外湖之&quot;界&quot;，桥畔原为耕织图景区</td></tr><tr><td style="text-align:left;"><strong>豳风桥</strong></td><td style="text-align:left;">三孔石桥上覆亭</td><td style="text-align:left;">名出《诗经·豳风》，寓劝课农桑；旧名&quot;桑苎桥&quot;，避咸丰帝名讳改今名</td></tr><tr><td style="text-align:left;"><strong>玉带桥</strong></td><td style="text-align:left;">高拱单孔石桥，汉白玉栏杆</td><td style="text-align:left;">六桥中最负盛名，拱高而薄如半环玉带，帝后龙舟须经此桥入湖</td></tr><tr><td style="text-align:left;"><strong>镜桥</strong></td><td style="text-align:left;">石桥覆八角亭</td><td style="text-align:left;">取&quot;两水夹明镜&quot;之意，桥亭观湖如照镜</td></tr><tr><td style="text-align:left;"><strong>练桥</strong></td><td style="text-align:left;">石桥覆长方亭</td><td style="text-align:left;">取谢朓&quot;澄江静如练&quot;诗意，形容湖水如白练平铺</td></tr><tr><td style="text-align:left;"><strong>柳桥</strong></td><td style="text-align:left;">三孔石桥</td><td style="text-align:left;">堤尽处柳丝拂水，&quot;柳桥&quot;之名直白而传神，春景最佳</td></tr></tbody></table><p>六桥之中，玉带桥最为出挑：桥身以青石与汉白玉砌成，单孔高拱，弧度圆润如玉带凌空，桥栏雕有仙鹤、云纹，通体洁白，在碧波垂柳间格外醒目。</p><p>相传帝后乘龙舟由后湖进入昆明湖，龙舟高大，唯有玉带桥的高拱方能通过，故桥孔特意加高——美观与实用，在这一弯弧线上达成了完美的和解。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="乾隆的-西湖情结" tabindex="-1">乾隆的&quot;西湖情结&quot; <a class="header-anchor" href="#乾隆的-西湖情结" aria-label="Permalink to &quot;乾隆的&quot;西湖情结&quot;&quot;">​</a></h3><p>乾隆十六年第一次南巡，驻跸杭州，泛舟西湖，对苏堤六桥流连忘返。回京后扩建昆明湖，他索性在湖西堆筑长堤，&quot;照抄&quot;苏堤六桥的格局，并逐桥题名、逐桥题诗。玉带桥畔的御碑上刻着他反复吟咏的诗句：&quot;螺黛一丸银盆叠，玉带千尺金堤拖。&quot;</p><p>此后六次南巡，乾隆每次都到西湖&quot;验收作业&quot;，回京再微调西堤——这道堤，是帝王写给西湖的一封长达三十年、七次往返的情书。</p><h3 id="避讳改名的豳风桥" tabindex="-1">避讳改名的豳风桥 <a class="header-anchor" href="#避讳改名的豳风桥" aria-label="Permalink to &quot;避讳改名的豳风桥&quot;">​</a></h3><p>豳风桥原名&quot;桑苎桥&quot;，取种桑植苎、男耕女织之意，与西堤旁的&quot;耕织图&quot;景区呼应。然而咸丰帝名&quot;奕詝&quot;，&quot;苎&quot;与&quot;詝&quot;同音，犯了御名忌讳，于是桥名被改为&quot;豳风&quot;，典出《诗经·豳风·七月》中&quot;蚕月条桑&quot;的农事篇章——虽改了名，劝农的立意却换了个出处保存下来。一座小桥的名字变迁，藏着清宫避讳制度的活样本。</p><h3 id="界湖桥边的-水操学堂" tabindex="-1">界湖桥边的&quot;水操学堂&quot; <a class="header-anchor" href="#界湖桥边的-水操学堂" aria-label="Permalink to &quot;界湖桥边的&quot;水操学堂&quot;&quot;">​</a></h3><p>西堤最北的界湖桥畔，原有乾隆设立的&quot;耕织图&quot;景区，以稻田桑畦象征男耕女织。1886年慈禧重建清漪园时，偏偏选中这块地设立&quot;昆明湖水操学堂&quot;，对外宣称&quot;恢复乾隆朝水师操练旧制&quot;，以此为由头动用海军经费修园。学堂确实办了几期，学员不过数十人，湖上的&quot;水操&quot;也多是排场。名义上的学堂、实质上的园林工程——界湖桥下的这片水，见证了晚清最著名的一次&quot;公款挪用&quot;。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>玉带桥</strong>：六桥之首，高拱如带，汉白玉栏杆映碧波，是全园最上镜的桥梁，无之一。</li><li><strong>桥桥有景</strong>：一堤六桥形制无一雷同，建议从北向南逐桥慢行，比较各桥的亭制、拱形与题名碑刻。</li><li><strong>西堤春晓</strong>：三月中旬至四月中旬，堤上数十株山桃与岸柳同放，&quot;桃红柳绿&quot;映玉带桥，是颐和园春天的颜值巅峰。</li><li><strong>湖上双堤</strong>：从玉带桥或柳桥上东望，昆明湖、东堤、十七孔桥、佛香阁层层入画；西望则玉泉山塔借景而来，&quot;一堤担两山&quot;的格局尽收眼底。</li><li><strong>御题诗碑</strong>：桥头原立乾隆诗碑（部分为复制品），读一读帝王为每座桥写下的注脚，方知桥名皆是典故。</li></ol><h2 id="四季看桥" tabindex="-1">四季看桥 <a class="header-anchor" href="#四季看桥" aria-label="Permalink to &quot;四季看桥&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">景致</th></tr></thead><tbody><tr><td style="text-align:left;">春</td><td style="text-align:left;">山桃夹岸、柳浪闻莺，玉带桥畔最出片</td></tr><tr><td style="text-align:left;">夏</td><td style="text-align:left;">堤柳成荫、荷风送爽，桥亭宜避暑听雨</td></tr><tr><td style="text-align:left;">秋</td><td style="text-align:left;">芦荻萧萧、水天一色，练桥&quot;白练&quot;意境最浓</td></tr><tr><td style="text-align:left;">冬</td><td style="text-align:left;">雪后长堤银装素裹，&quot;西堤雪霁&quot;为园中胜景</td></tr></tbody></table><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>玉带桥西岸</strong>：清晨无风时拍桥身与倒影合成完整玉环，全园最佳机位。</li><li><strong>柳桥畔</strong>：下午顺光，长堤、桃柳与远处佛香阁同框，标准&quot;西堤春晓&quot;。</li><li><strong>镜桥亭中</strong>：以桥亭飞檐为前景框出湖景，别有层次。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>西堤全长约2.7公里，步行贯穿约需1-1.5小时；全程平路无坡，适合慢行与摄影。</li><li>最佳季节是春季桃花盛开时（3月中旬-4月中旬），其次是盛夏（堤柳成荫）与初雪之后（&quot;西堤雪霁&quot;）。</li><li>西堤位置偏远、人少清净，是避开旅行团的最佳去处；缺点是离主要景点较远，建议与<a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">昆明湖</a>游船组合安排。</li><li>堤上树荫虽多但全程无补给点，夏季行走请备足饮水；堤面石板雨后湿滑，玉带桥坡度较陡，雨雪天慢行。</li><li>桃花季周末人流量极大，想拍空镜的摄影爱好者建议工作日清晨前往。</li><li>走完西堤可经南端堤口转入东堤，顺路看<a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">十七孔桥</a>，完成环湖精华段。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：西堤全程有多远？</strong></p><p>约2.7公里，平路无坡，步行贯穿需1-1.5小时；边走边拍、桥亭歇脚的话要留足2小时。</p><p><strong>Q：玉带桥为什么拱这么高？</strong></p><p>相传帝后龙舟由后湖驶入昆明湖必须从此桥下通过，龙舟高大，桥孔只能加高——于是有了这弯&quot;玉带&quot;。</p><p><strong>Q：春天看桃花什么时候最好？</strong></p><p>3月中旬至4月中旬，清明前后山桃最盛；桃花季的周末西堤堪比庙会，想清静请赶工作日清晨。</p><p><strong>Q：西堤沿线有厕所和饮水点吗？</strong></p><p>西堤商业设施极少，几乎没有补给点。出发前请在北宫门、新建宫门等入口处解决如厕和购水问题。</p><hr><p><strong>📍 位置</strong>：昆明湖西部堤道，北接玉带桥一线，纵贯湖西 <strong>⏱️ 建议游览</strong>：1-1.5小时 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',40)])])}const f=e(r,[["render",i]]);export{h as __pageData,f as default};
